create extension if not exists pgcrypto;
alter table if exists public.profiles add column if not exists is_guest boolean not null default false, add column if not exists ip_hash text;
create sequence if not exists public.guest_nickname_seq start 1;
create or replace function public.allocate_guest_nickname() returns text language sql security definer set search_path=public as $$ select 'Misafir '||nextval('public.guest_nickname_seq')::text; $$;
grant execute on function public.allocate_guest_nickname() to authenticated,service_role;
create table if not exists public.ip_bans(id uuid primary key default gen_random_uuid(),ip_hash text not null unique,reason text,created_by uuid references auth.users(id),created_at timestamptz not null default now(),expires_at timestamptz);
create table if not exists public.raffle_managers(user_id uuid primary key references auth.users(id) on delete cascade,granted_by uuid references auth.users(id),created_at timestamptz not null default now());
create table if not exists public.raffles(id uuid primary key default gen_random_uuid(),title text not null,description text not null,prize text not null,rules text,status text not null default 'draft' check(status in('draft','active','completed','cancelled')),starts_at timestamptz not null,ends_at timestamptz not null,winner_count integer not null default 1 check(winner_count between 1 and 100),created_by uuid references auth.users(id),drawn_by uuid references auth.users(id),drawn_at timestamptz,created_at timestamptz not null default now());
create table if not exists public.raffle_entries(id uuid primary key default gen_random_uuid(),raffle_id uuid not null references public.raffles(id) on delete cascade,user_id uuid not null references auth.users(id) on delete cascade,display_name text not null,is_valid boolean not null default true,created_at timestamptz not null default now(),unique(raffle_id,user_id));
create table if not exists public.raffle_winners(id uuid primary key default gen_random_uuid(),raffle_id uuid not null references public.raffles(id) on delete cascade,entry_id uuid references public.raffle_entries(id),user_id uuid references auth.users(id),display_name text not null,position integer not null,drawn_by uuid references auth.users(id),created_at timestamptz not null default now(),unique(raffle_id,position));
alter table public.raffles enable row level security;alter table public.raffle_entries enable row level security;alter table public.raffle_winners enable row level security;alter table public.raffle_managers enable row level security;alter table public.ip_bans enable row level security;
drop policy if exists "raffles public read" on public.raffles;create policy "raffles public read" on public.raffles for select using(status in('active','completed'));
drop policy if exists "raffle entries authenticated insert" on public.raffle_entries;create policy "raffle entries authenticated insert" on public.raffle_entries for insert to authenticated with check(auth.uid()=user_id);
drop policy if exists "raffle entries own read" on public.raffle_entries;create policy "raffle entries own read" on public.raffle_entries for select to authenticated using(auth.uid()=user_id);
drop policy if exists "raffle winners public read" on public.raffle_winners;create policy "raffle winners public read" on public.raffle_winners for select using(true);
